function extractJsonObject(responseText: string): string {
	const trimmed = responseText.trim();
	if (!trimmed) {
		throw new Error("response was empty");
	}

	const fencedMatch = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
	if (fencedMatch?.[1]) {
