		if (content.length === 0) {
			return {
				path: agentsPath,
				content,
				history: [],
			};
		}

		const userMessage = [
			"Repository guidance from the top-level AGENTS.md file.",
			"Follow this guidance for the rest of the task.",
			"",
			"AGENTS.md:",
			"",
			content,
		].join("\n");

		return {
			path: agentsPath,
			content,
			history: [
				{
					role: "user",
					parts: [{ text: userMessage }],
				},
				{
					role: "model",
					parts: [
						{
							text: "Understood. I will follow the repository guidance from AGENTS.md.",
						},
					],
				},
			],
		};
